const s=[{analysis_type:"monthly_brief",title:"March 2026 Market Brief: Strong Shipments, Pricing Firming",summary:"March shipments reached 282M lbs, up 6.4% YoY. Export demand from India and EU drove volumes. Nonpareil 23/25 firmed to $3.66/lb. Uncommitted supply at 518M lbs suggests tightening into Q2.",full_analysis:"The March 2026 Position Report shows continued momentum in the California almond market. Total shipments of 282M lbs represent a 6.4% increase over March 2025, with exports up 6.7% at 190M lbs. Domestic shipments held steady at 92M lbs. The sold position (shipped + committed) now stands at 85.7% of supply, well ahead of the 5-year average of 82.1% at this point in the crop year. New commitments of 290M lbs signal sustained buyer interest. With uncommitted inventory at just 518M lbs, pricing pressure is building. Nonpareil 23/25 whole natural has firmed to $3.66/lb, up 8% from October lows. MAXONS margin opportunity: buyers who locked in Q4 pricing are sitting on favorable positions.",confidence:.92,tags:["shipments","pricing","supply","monthly"],is_actionable:!0,created_at:"2026-04-15T08:00:00Z"},{analysis_type:"trade_signal",title:"BUY Signal: Nonpareil 23/25 — Price Momentum Accelerating",summary:"Nonpareil 23/25 has risen 8% since October, now at $3.66/lb. With sold position at 86% and strong India demand, further upside likely through June. Recommend forward purchases for Q3 delivery.",full_analysis:"Technical indicators and fundamental data both point to continued Nonpareil price appreciation. The sold position of 85.7% is the highest at this crop-year stage since 2021/22. India has increased almond imports 12% YoY, with Nonpareil grades commanding premium pricing in Mumbai and Delhi markets. The 2025/26 crop at 2.8B lbs is adequate but not excessive. With USDA projecting 2026/27 bearing acreage flat, supply constraints will persist. MAXONS trading desk should consider forward purchases at current levels for Q3 delivery windows.",confidence:.85,tags:["nonpareil","buy-signal","india","forward"],is_actionable:!0,created_at:"2026-04-14T14:30:00Z"},{analysis_type:"trend_alert",title:"India Export Surge: +12% YoY Through March",summary:"India has emerged as the dominant growth driver for California almonds in 2025/26. Cumulative exports to India through March are up 12% YoY, reaching approximately 380M lbs. Favorable rupee stability and growing middle-class demand are key factors.",full_analysis:"India remains the largest single export destination for California almonds and is driving the current crop year's strong export performance. Through March 2026, India-bound shipments are tracking ~12% ahead of the prior year. Key drivers include: (1) INR/USD stability near 83-84 range, (2) growing organized retail distribution, (3) health-conscious consumer trends in Tier 1 and Tier 2 cities. The Diwali and wedding season pipeline (Aug-Nov) will be the next major demand catalyst. MAXONS should maintain India buyer relationships as a strategic priority.",confidence:.88,tags:["india","exports","trend","growth"],is_actionable:!1,created_at:"2026-04-13T10:15:00Z"},{analysis_type:"anomaly",title:"Alert: Uncommitted Supply Below 5-Year Average",summary:"At 518M lbs, uncommitted supply for 2025/26 is 7.3% below the 5-year March average of 559M lbs. This tightness typically precedes a $0.15-0.25/lb price increase through harvest.",full_analysis:"Historical analysis of crop year supply positions shows that when March uncommitted inventory falls more than 5% below the 5-year average, prices tend to firm $0.15-0.25/lb through the July-August harvest period. The current 518M lbs uncommitted represents just 14.3% of total supply, compared to 15.4% average. This structural tightness is being compounded by strong Q1 export commitments. Buyers should be aware that spot availability for June-July delivery may be limited, with premiums likely for prompt shipment.",confidence:.82,tags:["supply","uncommitted","anomaly","tightness"],is_actionable:!0,created_at:"2026-04-12T16:45:00Z"},{analysis_type:"trade_signal",title:"EU Market Opportunity: Blanched Premium at 18-Month High",summary:"Blanched Nonpareil 23/25 premium over whole natural has widened to $0.42/lb, the highest spread since October 2024. EU confectionery demand driving the gap. MAXONS value-add opportunity.",full_analysis:"The blanched-to-whole premium spread for Nonpareil 23/25 has expanded to $0.42/lb (currently $4.08 blanched vs $3.66 whole natural). This premium is driven by strong EU confectionery sector demand, particularly from Germany, Spain, and Italy, where blanched almonds are the preferred input for marzipan, pralines, and bakery applications. For MAXONS, this presents a value-add opportunity: sourcing whole natural and arranging blanching adds roughly $0.18/lb in processing cost, yielding an incremental $0.24/lb margin above standard trading margins.",confidence:.79,tags:["eu","blanched","premium","value-add"],is_actionable:!0,created_at:"2026-04-11T09:20:00Z"},{analysis_type:"monthly_brief",title:"February 2026 Market Brief: Record Export Month",summary:"February exports hit 182M lbs, a record for the month. Total shipments of 270M lbs were up 7.1% YoY. New commitments of 277M lbs indicate pipeline remains robust heading into spring.",full_analysis:"February 2026 marked a record month for California almond exports at 182M lbs, surpassing the previous February record of 175M lbs set in January's report cycle. Total crop year shipments through February reached a cumulative pace suggesting the industry is on track to ship 2.6B+ lbs for 2025/26, which would be near-record territory. The strong shipment pace is drawing down available supply faster than typical, supporting the pricing firmness observed across all major varieties.",confidence:.9,tags:["shipments","exports","record","monthly"],is_actionable:!1,created_at:"2026-03-18T08:00:00Z"},{analysis_type:"trend_alert",title:"Mission Variety Gaining Share in Middle East Markets",summary:"Mission almond shipments to Middle East are up 18% YoY. The variety's distinctive flavor profile is gaining traction in UAE and Saudi Arabia retail channels.",full_analysis:"Mission almonds, which represent roughly 3% of the California crop, are seeing outsized demand growth in Middle East markets. UAE imports of Mission variety are estimated up 18% YoY, driven by premium retail positioning and the variety's naturally darker skin and richer flavor that appeals to regional palates. Saudi Arabia is also showing increased interest. For MAXONS (Dubai-based), this is a strategic home-market opportunity — sourcing Mission at $2.95/lb with a 3% margin and leveraging local distribution knowledge could be a high-margin niche play.",confidence:.76,tags:["mission","middle-east","uae","niche"],is_actionable:!0,created_at:"2026-04-10T11:30:00Z"},{analysis_type:"anomaly",title:"Carmel/Monterey Spread Narrowing — Substitution Risk",summary:"The price gap between Carmel ($2.94/lb) and Monterey ($2.86/lb) has narrowed to just $0.08/lb, down from the typical $0.15-0.20 spread. Buyers may substitute, impacting order patterns.",full_analysis:"Carmel and Monterey varieties serve overlapping market segments (industrial/ingredient use). Historically, Carmel commands a $0.15-0.20/lb premium over Monterey due to its slightly superior kernel characteristics. The current $0.08 spread suggests either Carmel oversupply or Monterey tightness. If the spread compresses further, industrial buyers may shift orders from Carmel to Monterey, creating unexpected demand pressure on Monterey and softening Carmel. MAXONS traders should monitor this spread weekly and be prepared to adjust sourcing recommendations.",confidence:.73,tags:["carmel","monterey","spread","substitution"],is_actionable:!1,created_at:"2026-04-09T15:00:00Z"}];async function n(a){const{count:e}=await a.from("ai_analyses").select("*",{count:"exact",head:!0});if(e&&e>0)return console.log(`ai_analyses already has ${e} rows, skipping seed`),!1;const r=s.map(t=>({...t,data_context:{source:"seed",model:"claude-opus-4-6"}})),{error:i}=await a.from("ai_analyses").insert(r);return i?(console.error("Seed ai_analyses error:",i.message),!1):(console.log(`✓ Seeded ${r.length} ai_analyses records`),!0)}export{n as s};
